import math

class LightweightRAGIndex:
    def __init__(self):
        self.documents = []
        self.vectors = []

    def trigrams(self, text):
        t = text.lower()
        vec = {}
        for i in range(len(t) - 2):
            tri = t[i:i+3]
            vec[tri] = vec.get(tri, 0) + 1
        return vec

    def cosine_sim(self, a, b):
        shared = set(a) & set(b)
        dot = sum(a[k] * b[k] for k in shared)
        mag_a = math.sqrt(sum(v**2 for v in a.values()))
        mag_b = math.sqrt(sum(v**2 for v in b.values()))
        if mag_a == 0 or mag_b == 0:
            return 0.0
        return round(dot / (mag_a * mag_b), 3)

    def add_documents(self, docs):
        for doc in docs:
            self.documents.append(doc)
            self.vectors.append(self.trigrams(doc))

    def search(self, query, top_k=3, threshold=0.0, use_prefix=False):
        q_text = ('query: ' + query) if use_prefix else query
        q_vec = self.trigrams(q_text)
        scored = []
        for doc, vec in zip(self.documents, self.vectors):
            s = self.cosine_sim(q_vec, vec)
            if s >= threshold:
                scored.append({"document": doc, "score": s})
        scored.sort(key=lambda x: x["score"], reverse=True)
        results = scored[:top_k]
        for i, r in enumerate(results):
            r["rank"] = i + 1
        return results

    def memory_report(self):
        all_tri = set()
        for v in self.vectors:
            all_tri.update(v.keys())
        return {"num_docs": len(self.documents), "unique_trigrams": len(all_tri)}

